solution: class Solution {
public:
    string strWithout3a3b(int a, int b) {
        string res;
        while (a || b) {
            bool writeA = false;
            int n = res.size();
            if (a > b) {
                if (n < 2 || !(res[n-1] == 'a' && res[n-2] == 'a')) {
                    writeA = true;
                }
            } else if (b > a) {
                if (n < 2 || !(res[n-1] == 'b' && res[n-2] == 'b')) {
                    writeA = false;
                } else {
                    writeA = true;
                }
            } else {
                if (n < 2 || res[n-1] != 'a') {
                    writeA = true;
                } else {
                    writeA = false;
                }
            }
            if (writeA) {
                res += 'a';
                --a;
            } else {
                res += 'b';
                --b;
            }
        }
        return res;
    }
};
